(function(w){"use strict";const ID="electrical-power";function compute(x){const v=Number(x.voltage),i=Number(x.current);if(!Number.isFinite(v)||!Number.isFinite(i))return{error:"전압과 전류를 입력해 주세요."};return{value:v*i};}
function render(root,api){root.innerHTML=`<div class="hm-calc-panel"><div class="hm-calc-form"><div class="hm-calc-grid-2"><div class="hm-calc-field"><label>전압 (V)</label><input class="hm-calc-input" inputmode="decimal" data-key="voltage" placeholder="" value=""></div><div class="hm-calc-field"><label>전류 (A)</label><input class="hm-calc-input" inputmode="decimal" data-key="current" placeholder="" value=""></div></div><div class="hm-calc-actions"><button type="button" class="hm-calc-btn">계산하기</button></div><p class="hm-calc-message" hidden></p></div><div class="hm-calc-result" hidden></div></div>`;const inputs=Array.prototype.slice.call(root.querySelectorAll("input[data-key]")),go=root.querySelector("button"),msg=root.querySelector(".hm-calc-message"),res=root.querySelector(".hm-calc-result");go.addEventListener("click",()=>{const x={};inputs.forEach(i=>x[i.dataset.key]=api.parseNumber(i.value));const r=compute(x);if(r.error){api.setMessage(msg,r.error);api.clearResult(res);return}api.setMessage(msg,"");api.setResult(res,api.resultCard("전력",`${api.formatNumber(r.value,8)} W`,"P = V × I"));});}
w.HM_CALC.register(ID,{compute,render});})(window);
